#include <bits/stdc++.h>
using namespace std;
int main(){
    int a,b;
    cin>>a>>b;
    unsigned long long sum=1;
    if(a==1){
        cout<<1;return 0;
    }
    for(int i=1;i<=b;i++){
        sum*=a;
        if(sum>1e9){
            cout<<-1;
            return 0;
        }
    }
    cout<<sum;
    return 0;
}
